const { ApolloServer, gql } = require('apollo-server-express');
const express = require('express');

// Mock data
const users = [
  { id: '1', name: 'Alice', email: 'alice@example.com' },
  { id: '2', name: 'Bob', email: 'bob@example.com' },
  { id: '3', name: 'Charlie', email: 'charlie@example.com' }
];

const posts = [
  { id: '1', title: 'First Post', content: 'Content 1', userId: '1' },
  { id: '2', title: 'Second Post', content: 'Content 2', userId: '2' },
  { id: '3', title: 'Third Post', content: 'Content 3', userId: '1' }
];

const comments = [
  { id: '1', content: 'Great post!', postId: '1', userId: '2' },
  { id: '2', content: 'Thanks for sharing', postId: '1', userId: '3' },
  { id: '3', content: 'I agree', postId: '2', userId: '1' }
];

// Schema definition
const typeDefs = gql`
  type User {
    id: ID!
    name: String!
    email: String!
    posts: [Post!]!
    comments: [Comment!]!
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    user: User!
    comments: [Comment!]!
  }

  type Comment {
    id: ID!
    content: String!
    user: User!
    post: Post!
  }

  type Query {
    users: [User!]!
    posts: [Post!]!
    comments: [Comment!]!
    user(id: ID!): User
    post(id: ID!): Post
    comment(id: ID!): Comment
  }
`;

// Resolvers
const resolvers = {
  Query: {
    users: () => users,
    posts: () => posts,
    comments: () => comments,
    user: (_, { id }) => users.find(user => user.id === id),
    post: (_, { id }) => posts.find(post => post.id === id),
    comment: (_, { id }) => comments.find(comment => comment.id === id)
  },
  User: {
    posts: (user) => posts.filter(post => post.userId === user.id),
    comments: (user) => comments.filter(comment => comment.userId === user.id)
  },
  Post: {
    user: (post) => users.find(user => user.id === post.userId),
    comments: (post) => comments.filter(comment => comment.postId === post.id)
  },
  Comment: {
    user: (comment) => users.find(user => user.id === comment.userId),
    post: (comment) => posts.find(post => post.id === comment.postId)
  }
};

// Create Apollo Server
const server = new ApolloServer({
  typeDefs,
  resolvers,
  // Security: Add query depth limiting
  validationRules: [
    // Limit query depth to prevent deeply nested queries
    require('graphql-depth-limit')(10),
    // Limit total complexity
    require('graphql-cost-analysis')({
      maximumCost: 1000,
      defaultCost: 1,
      onComplete: (cost) => {
        // Log or handle cost analysis
      }
    })
  ],
  // Security: Disable introspection in production
  introspection: process.env.NODE_ENV !== 'production',
  // Security: Disable playground in production
  playground: process.env.NODE_ENV !== 'production'
});

// Security: Add rate limiting middleware
const rateLimit = require('express-rate-limit');
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100 // limit each IP to 100 requests per windowMs
});

const app = express();
app.use(limiter);

// Security: Add helmet for HTTP headers
const helmet = require('helmet');
app.use(helmet());

// Security: Add CORS
const cors = require('cors');
app.use(cors());

// Security: Add body size limit
app.use(express.json({ limit: '10mb' }));
app.use(express.urlencoded({ limit: '10mb', extended: true }));

// Security: Add input validation
const { body, validationResult } = require('express-validator');

// Apply security middleware to GraphQL endpoint
app.use('/graphql', (req, res, next) => {
  // Validate input
  if (req.body.query) {
    // Basic validation to prevent malicious queries
    if (req.body.query.includes('introspection') || req.body.query.includes('__schema')) {
      return res.status(400).json({ error: 'Invalid query' });
    }
  }
  next();
});

// Start server
async function startServer() {
  await server.start();
  server.applyMiddleware({ app, path: '/graphql' });
  
  const PORT = process.env.PORT || 4000;
  app.listen(PORT, () => {
    console.log(`Server running at http://localhost:${PORT}${server.graphqlPath}`);
  });
}

startServer().catch(error => {
  console.error('Error starting server:', error);
});